<?php
 declare(strict_types=1);
require __DIR__ . '/app.php';
require __DIR__ . '/training-storage.php';
$config=lqr_config();$state=lqr_load_state();$userId=lqr_current_user_id($config);$user=lqr_get_user($state,$config,$userId);
$slug=trim((string)($_GET['campaign']??$_POST['campaign']??'5-day-movement-challenge'));$taskSlug=trim((string)($_GET['task']??$_POST['task']??''));$campaign=tcl_storage_campaign_by_slug($slug);$error='';$message='';$participant=null;$task=null;$sequenceSlug='';
if($campaign){foreach((array)($campaign['sequence']['steps']??[]) as $s){if(($s['slug']??'')===$taskSlug){$task=$s;$sequenceSlug=(string)($campaign['sequence']['slug']??'sequence');break;}}}
try{$participant=$campaign?tcl_participant_required($slug,$user):null;}catch(Throwable $e){$error=$e->getMessage();}
if(($_SERVER['REQUEST_METHOD']??'GET')==='POST' && ($_POST['tcl_action']??'')==='upload' && $campaign && $task && $participant){try{ $note=['participant_note'=>(string)($_POST['participant_note']??'')]; $fileMeta=['original_filename'=>'text-note.txt','stored_filename'=>'text-note-'.time().'.txt','storage_path'=>'text-note','file_extension'=>'txt','mime_type'=>'text/plain','file_size_bytes'=>0]; if(($task['proof']??'')!=='text' && isset($_FILES['proof_file']) && is_array($_FILES['proof_file']) && (int)$_FILES['proof_file']['error']!==UPLOAD_ERR_NO_FILE){ if((int)$_FILES['proof_file']['error']!==UPLOAD_ERR_OK)throw new RuntimeException('Upload failed. Try again.'); $original=(string)$_FILES['proof_file']['name']; $ext=strtolower(pathinfo($original,PATHINFO_EXTENSION)); $allowed=array_filter(array_map('trim',explode(',',(string)($task['accepted_extensions']??'jpg,jpeg,png,webp,mp4,mov,webm')))); if($allowed && !in_array($ext,$allowed,true))throw new RuntimeException('Unsupported file type.'); $maxMb=(int)($task['max_file_size_mb']??50); if($maxMb>0 && (int)$_FILES['proof_file']['size']>($maxMb*1024*1024))throw new RuntimeException('File is larger than the allowed size.'); $dir=__DIR__.'/uploads/training-proof'; if(!is_dir($dir))@mkdir($dir,0775,true); $stored=tcl_public_id().'.'.$ext; $dest=$dir.'/'.$stored; if(!move_uploaded_file((string)$_FILES['proof_file']['tmp_name'],$dest))throw new RuntimeException('Unable to store uploaded file.'); $fileMeta=['original_filename'=>$original,'stored_filename'=>$stored,'storage_path'=>'uploads/training-proof/'.$stored,'file_extension'=>$ext,'mime_type'=>(string)($_FILES['proof_file']['type']??''),'file_size_bytes'=>(int)$_FILES['proof_file']['size']]; } elseif(($task['proof']??'')!=='text'){ throw new RuntimeException('Select a proof file before submitting.'); } $submission=tcl_save_submission($participant,$slug,$sequenceSlug,$taskSlug,$fileMeta,$note); $message='Proof submitted for review. Submission '.$submission['id']; }catch(Throwable $e){$error=$e->getMessage();}}
$latest=$participant&&$task?tcl_latest_submission_for_task((string)$participant['id'],$slug,$taskSlug):null;
