lqr_h($taskSlug)?>"><div class="tcl-card-head"><div><h2>Submit proof</h2><p>Accepted: <?=lqr_h((string)($task['accepted_extensions']??'text note'))?> · Max <?=number_format((int)($task['max_file_size_mb']??0))?> MB</p></div><span class="tcl-pill is-warning">Pending review after submit</span></div><?php if(($task['proof']??'')!=='text'):?><label class="tcl-empty" style="display:block;text-align:left"><strong>Proof file</strong><br><input type="file" name="proof_file" style="margin-top:12px;width:100%"></label><?php endif;?><label style="display:block;margin-top:16px"><strong>Participant note</strong><textarea name="participant_note" rows="5" style="width:100%;margin-top:8px;border:1px solid #dbe4f0;border-radius:14px;padding:12px"></textarea></label><div class="tcl-actions" style="margin-top:16px"><button class="tcl-btn primary" type="submit">Submit Proof</button><a class="tcl-btn" href="training-sequence.php?campaign=<?=urlencode($slug)?>">Cancel</a></div></form><aside class="tcl-card soft"><h2>Latest submission</h2><?php if($latest):?><p><strong>Status:</strong> <?=lqr_h(tcl_status_label((string)$latest['status']))?></p><p><strong>Attempt:</strong> <?=number_format((int)$latest['attempt_number'])?></p><p><strong>Submitted:</strong> <?=lqr_h((string)$latest['submitted_at'])?></p><p><strong>File:</strong> <?=lqr_h((string)($latest['file']['original_filename']??'text note'))?></p><?php else:?><div class="tcl-empty">No submission yet.</div><?php endif;?></aside></section><?php endif;?></main></div><nav class="tcl-bottom-nav"><a href="training-lab.php"><span>⌂</span>Overview</a><a href="training-campaigns.php"><span>◆</span>Campaigns</a><a href="training-sequence.php?campaign=<?=urlencode($slug)?>"><span>▤</span>Tasks</a><a class="active" href="#"><span>⇧</span>Proof</a><a href="wallet.php"><span>◎</span>Wallet</a></nav><script src="assets/training-lab.js"></script></body></html>
